create table maxprint_dev.psx_stocks (
    id               number generated by default on null as identity not null enable,
    symbol           varchar2(50 byte),
    name             varchar2(255 byte),
    sector           varchar2(255 byte),
    is_kmi30         varchar2(1 byte),
    sector_p_e       number,
    price            number,
    eps_annual       number,
    eps_latest       varchar2(50 byte),
    p_e              number,
    exp_p_e          number,
    price_to_bv      number,
    roe              number,
    roa              number,
    dividend_yeild   number,
    avg_52_weeks_vol number,
    comet_rnaking    number,
    chatgpt_ranking  number
);

alter table maxprint_dev.psx_stocks add primary key ( id )
    using index enable;


